SELECT refund_amount 
FROM refunds 
WHERE student_id = 1;

SELECT student_name
FROM students
WHERE student_id IN (SELECT student_id FROM refunds);

SELECT level_name 
FROM academic_levels 
ORDER BY level_name ASC;

SELECT MAX(late_fee) AS highest_late_fee
FROM tuition_fees
WHERE level_id = 4;

SELECT SUM(regular_fee)
FROM tuition_fees
WHERE level_id = 1;

SELECT student_id, student_name
FROM students
WHERE STRFTIME('%Y', 'now') - STRFTIME('%Y', date_of_birth) > 35;

SELECT s.student_name, al.level_name
FROM students s
INNER JOIN academic_levels al ON s.academic_level = al.level_id;
